+-        try {
+-            leaf_node& child = dynamic_cast< leaf_node& >(
+-                *(*child_iter).second);
+-            return &child;
+-        } catch (const std::bad_cast& unused_error) {
++        leaf_node* child = dynamic_cast< leaf_node* >((*child_iter).second);
